ALTER TABLE "HealthInsuranceProvider" ADD CONSTRAINT "HealthInsuranceProvider_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "HealthPatientInsuranceCoverage" ADD CONSTRAINT "HealthPatientInsuranceCoverage_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "HealthPatientInsuranceCoverage" ADD CONSTRAINT "HealthPatientInsuranceCoverage_organizationId_patientId_fkey" FOREIGN KEY ("organizationId","patientId") REFERENCES "HealthPatient"("organizationId","id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "HealthPatientInsuranceCoverage" ADD CONSTRAINT "HealthPatientInsuranceCoverage_organizationId_insuranceProviderId_fkey" FOREIGN KEY ("organizationId","insuranceProviderId") REFERENCES "HealthInsuranceProvider"("organizationId","id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "HealthCoverageRequest" ADD CONSTRAINT "HealthCoverageRequest_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "HealthCoverageRequest" ADD CONSTRAINT "HealthCoverageRequest_organizationId_patientId_fkey" FOREIGN KEY ("organizationId","patientId") REFERENCES "HealthPatient"("organizationId","id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "HealthCoverageRequest" ADD CONSTRAINT "HealthCoverageRequest_organizationId_patientCoverageId_fkey" FOREIGN KEY ("organizationId","patientCoverageId") REFERENCES "HealthPatientInsuranceCoverage"("organizationId","id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "HealthCoverageRequest" ADD CONSTRAINT "HealthCoverageRequest_organizationId_insuranceProviderId_fkey" FOREIGN KEY ("organizationId","insuranceProviderId") REFERENCES "HealthInsuranceProvider"("organizationId","id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "HealthCoverageRequestEvent" ADD CONSTRAINT "HealthCoverageRequestEvent_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "HealthCoverageRequestEvent" ADD CONSTRAINT "HealthCoverageRequestEvent_organizationId_coverageRequestId_fkey" FOREIGN KEY ("organizationId","coverageRequestId") REFERENCES "HealthCoverageRequest"("organizationId","id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "HealthCoverageRequestEvent" ADD CONSTRAINT "HealthCoverageRequestEvent_actorUserId_fkey" FOREIGN KEY ("actorUserId") REFERENCES "User"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
UPDATE "EnterprisePosition" SET "permissionsJson"=COALESCE("permissionsJson",'[]'::jsonb)||'["health.insurance.view","health.insurance.view_sensitive","health.insurance.manage_providers","health.insurance.manage_patient_coverages","health.insurance.create_coverage_request","health.insurance.update_coverage_request","health.insurance.submit_coverage_request","health.insurance.approve_coverage_request","health.insurance.reject_coverage_request","health.insurance.cancel_coverage_request","health.insurance.apply_to_invoice","health.insurance.manage_documents","health.insurance.view_reports"]'::jsonb WHERE "positionCode" IN ('INSURANCE_AGENT','ADMIN_MANAGER') AND "sectorId" IN (SELECT "id" FROM "BusinessSector" WHERE "code"='HEALTH_CARE');
